var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제법이군요. 거울로 복제한 무기를 부수다니.","JPN":"やりますね。鏡で複製した武器を壊すなんて。","ENG":"Impressive. To think you destroyed weapons replicated by the mirror.","TWN":"真厲害，居然能破壞用鏡子複製出來的武器。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그러게. 지난 번에 싸웠을 땐 당신이 쓰는 내 검에 압도 당하는 기분이었거든...","JPN":"そうだね。この前戦った時はあなたの使う私の剣に圧倒される気分だったけど……","ENG":"Yeah. Last time we fought, it felt like I was being overwhelmed by my own sword in your hands...","TWN":"是啊。上次交手時，我還覺得像是被你拿著我的劍壓著打……"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"하지만, 이번엔 틈이 보였어.","JPN":"でも、今回は隙が見えたから。","ENG":"But this time, I saw an opening.","TWN":"不過這次，我看見破綻了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"모방의 귀재라 해도, 한 번도 본 적 없는 타인의 기술을 단숨에 따라잡는 건 무리겠지.","JPN":"模倣の天才だとしても、一度も見たことのない他人の技術に一気に追いつくことは無理だろう。","ENG":"Even for a master of imitation, instantly copying techniques you've never seen before must be difficult.","TWN":"就算是模仿天才，還是辦不到瞬間學會從沒見過的他人技術吧。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"지금의 녀석은, 널 사전에 조사할 기회조차 없었을 테니 말이야.","JPN":"今のやつは、お前を事前調査する機会すらなかったはずだからな。","ENG":"Especially since this time, you wouldn't even have had the chance to study her in advance.","TWN":"現在的傢伙，連事先調查你的機會都沒有。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"뭐든 쉽게 베끼기만 하는 줄 알았는데. 당신도 사실은 노력파였구나?","JPN":"何でも簡単にコピーできるんだとばかり思ってたけど。あなたも実は努力家だったんだね？","ENG":"I thought you just copied everything easily. Turns out you're actually the hardworking type?","TWN":"我還以為你只會輕鬆地模仿別人，原來你其實也是努力型的啊？"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신들은 강하네요. 심지어 전력을 다하지도 않았어요.","JPN":"あなたたちは強いですね。しかも全力を出してもいませんでした。","ENG":"You're strong. And you're not even fighting at full strength.","TWN":"你們很強，甚至還沒有使出全力。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저보다 더 강한 존재를 상대할 여력을 남겨둘 정도의 수준은 된다는 거겠죠. 그거면 됐어요.","JPN":"私よりも強い存在を相手する力を温存できるレベルなのでしょう。それが確認できれば問題ありません。","ENG":"That means you still have enough left to face someone stronger than me. That's good enough.","TWN":"也就是說，你們的實力還足以保留力量去對付比我更強的存在。那樣就夠了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그럼, 승부에서 이겼으니 거울은 저희가 가져가겠습니다.","JPN":"じゃあ、勝負に勝ったので、鏡は私たちがもらっていきますね。","ENG":"Then since we won, we'll be taking the mirror.","TWN":"那麼，既然我們贏了，我們就帶走鏡子了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그건 소용없을 거에요.","JPN":"それを持っていっても何の役にも立ちませんよ。","ENG":"That won't be of any use.","TWN":"那是沒有用的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"...네? 소용이 없다뇨?","JPN":"……え？　役に立たない？","ENG":"...What? What do you mean it won't be of any use?","TWN":"……什麼？沒有用？"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신들이 지금까지 마주한 거울은 파노라마의 모방품일 뿐이니까요. 제 기능을 하기도 전에 사라질 겁니다.","JPN":"あなたたちが今まで見てきた鏡はパノラマの模倣品に過ぎませんので。機能する前に消えてしまいます。","ENG":"The mirror you've encountered so far is only an imitation of Panorama. It will disappear before it can even function properly.","TWN":"你們剛才遇到的那些鏡子，只是全景的仿製品而已。在發揮真正功能之前就會消失。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"엑, 이 거울이 거울에 비친 거울이었다고요? 그런 것도 되는 거였어요?","JPN":"えっ、この鏡が鏡に映った鏡だったんですか？　そんなこともできるんですか？","ENG":"W-wait, this mirror was just a mirror reflected in another mirror? That's possible?","TWN":"欸？那面鏡子是鏡子裡倒映的鏡子？這種事也做得到嗎？！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"...파노라마의 본체는 함선 내부의 아공간에 보관되고 있어요.","JPN":"……パノラマの本体は艦船内部の亜空間に保管されています。","ENG":"...The real Panorama is stored in a dimensional pocket inside the ship.","TWN":"……全景的本體，被保存在艦內的亞空間。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 조심하시길. 그 아공간은 타기리온의 영역이라서 어떤 위협이 숨어있을지 저도 모른답니다.","JPN":"ですが、お気をつけください。艦船内部の亜空間はタギリオンの領域ですので、どんな脅威が隠れているか私にも分かりません。","ENG":"But be careful. That subspace is part of Thagirion's domain, so even I don't know what dangers might be lurking there.","TWN":"不過要小心。那個亞空間是塔基里翁的領域，我也不知道裡面藏著什麼威脅。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"마왕의 사도가 자기 주인이 만든 공간을 모르다니.","JPN":"魔王の使徒が、自分の主の作った空間について知らないとはな。","ENG":"An Apostle of the Demon Lord who doesn't know what's inside a space created by her own master.","TWN":"身為魔王的使徒，卻不知道主人創造的空間。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"널 사도로 만들어 놓고도, 녀석은 애초에 널 믿은 적이 없었군.","JPN":"あいつはお前を使徒にしておきながら、最初から信じていなかったということか。","ENG":"So even after turning you into an Apostle, she never trusted you from the start.","TWN":"就算把你變成使徒，那傢伙從一開始就沒信任過你啊。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"심장을 빼앗긴 순간부터... 이용 당하고 버려지는, 그런 역할이었으니까요.","JPN":"心臓を奪われた瞬間から……利用されて捨てられる、そんな役でしたので。","ENG":"From the moment my heart was taken... I was only ever meant to be used and discarded.","TWN":"從心臟被奪走的那一刻起……我就只是被利用、最後被拋棄的角色而已。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"타기리온의 함정이 준비해뒀다고 해도 여기서 물러설 생각은 없어.","JPN":"タギリオンが罠を仕掛けていたとしても、ここで引き下がる気はないよ。","ENG":"Even if Thagirion prepared a trap, we have no intention of backing down here.","TWN":"就算塔基里翁準備了陷阱，我們也不會退縮。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"애당초, 타기리온과 담판을 지으려고 시작한 일이니까.","JPN":"そもそも、タギリオンと決着をつけるために始めたことだから。","ENG":"This all started because we intended to settle things with Thagirion in the first place.","TWN":"從一開始，就是為了跟塔基里翁正面對決。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"...그 눈빛.","JPN":"……その目。","ENG":"...That look in your eyes.","TWN":"……那個眼神。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신의 언니를 닮아 있군요.","JPN":"あなたのお姉さんに似ていますね。","ENG":"They resemble your sister's.","TWN":"跟你姐姐很像呢。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"뭐...? 그 사람을 알아?","JPN":"え……？　姉さんを知ってるの？","ENG":"What...? You know her?","TWN":"什麼……？你認識她？"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"왜 당신이 늑대라 불리는지, 생각해본 적 있나요?","JPN":"どうしてあなたがオオカミと呼ばれているのか、考えてみたことはありますか？","ENG":"Have you ever wondered why you're called a Wolf?","TWN":"你有想過，為什麼你會被稱為狼嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"탐미엘은 작은 파편 하나를 손에 넣기 위해 발버둥 치는 우리와 달리, 세피로트 나무 자체를 손에 넣은 자.","JPN":"タミエルは小さな破片一つを手に入れるためにあがいている私たちとは違い、セフィロト自体を手に入れた者。","ENG":"Unlike us, who struggle just to obtain a single Fragment, Tammiel is the one who obtained the Tree of Sephiroth itself.","TWN":"塔米爾和我們這些為了一塊小碎片拼命掙扎的人不同，她是得到整棵生命樹的人。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 나무의 권한으로 규칙을 창조해, 스스로 신이 된 자.","JPN":"その木の権限で規則を創造し、自ら神となった者。","ENG":"With the authority of that tree, she created rules and became a god herself.","TWN":"用那棵樹的權限創造規則，讓自己成為神。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고, 원하는 것을 얻기 위해 모든 것을 되풀이하는 자이기도 하죠.","JPN":"そして、望むものを手に入れるために、すべてを繰り返している者でもあります。","ENG":"And she is also someone who repeats everything in order to obtain what she desires.","TWN":"而且，她也是為了得到想要的東西，不斷重複一切的人。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"늑대인 당신은... 그녀의 ■■이 담긴 ■■.","JPN":"オオカミであるあなたは……彼女の■■が込められた■。","ENG":"You, the Wolf... are the ■■■■■■ that contains her ■■■■.","TWN":"身為狼的你……是承載著她■■的■■。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_WHITE_NOISE","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"안■된 ■련 속에서- ■■■ ■■을 ■에 ■■록 길들여진, ■■를 먹어 ■■는 짐■.","JPN":"準■された■練の中で……■■■■■■■を■に■■■よう手懐けられた、■■を食らい■■す■。","ENG":"Within a■■■■ged ■■ials, conditioned to ■■■■■ a ■■■■■■■■■ ■■te, a be■■■ that ■■vours the ■■■■■.","TWN":"在無法■■的■鎖鏈中—被馴養成為只為了■■■■■某種■存在而活■■，吞噬■■而延續■■的野獸■。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_WHITE_NOISE","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"스완...?","JPN":"スワン……？","ENG":"Swan...?","TWN":"史旺……？"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"무슨 일이야? 갑자기 왜 그래?!","JPN":"何なの？　いきなりどうしちゃったんだよ！？","ENG":"What's wrong? Why are you acting like this all of a sudden?!","TWN":"怎麼了？怎麼突然這樣？！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"기억하■■, 늑■.","JPN":"覚えておき■■■、オ■■ミ。","ENG":"Reme■■■■, Wo■■.","TWN":"記住■■，狼■。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"잡아■되... ■■먹히지 마요.","JPN":"■■■としても……食わ■■はいけません。","ENG":"Dev■■r... but do not be ■■voured.","TWN":"抓住■……不要被■■吞噬。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_WHITE_NOISE","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};